    def job_assigner(self, jobs, num_workers):
        jobs.sort(key=lambda x: x[1])
        max_assigned = 0
        assigned_workers = [0] * num_workers
        for job in jobs:
            for i in range(num_workers):
                if assigned_workers[i] + job[0] <= job[1]:
                    assigned_workers[i] += job[0]
                    max_assigned += 1
                    break
        return max_assigned

