class Solution {
public:
    int jobAssigner(vector<vector<int>>& jobs, int num_workers) {
        sort(jobs.begin(), jobs.end(), [](vector<int> a, vector<int> b) {
            return a[1] < b[1];
        });
        int max_assigned = 0;
        vector<int> assigned_workers(num_workers, 0);
        for (vector<int> job : jobs) {
            for (int i = 0; i < num_workers; i++) {
                if (assigned_workers[i] + job[0] <= job[1]) {
                    assigned_workers[i] += job[0];
                    max_assigned++;
                    break;
                }
            }
        }
        return max_assigned;
    }
};

int main() {
    vector<vector<int>> jobs = {{10, 5}, {2, 3}, {3, 4}, {3, 3}, {5, 4}, {1, 1}, {1, 1}, {3, 2}, {2, 1}, {1, 1}};
    int num_workers = 2;
    Solution solution;
    cout << solution.jobAssigner(jobs, num_workers) << endl;
    return 0;
}
